INSERT INTO `tbl_changelog` VALUES('11','office','1.2.2','Database Manager: Restoration & Hotfix','Restored full suite of Database Manager tools (SQL, History, Import, Export) as interactive tabs in the new workspace. Implemented AJAX-based feedback for imports and unique tab IDs for multiple query windows. Resolved a critical RouteNotFoundException with standardized bookmark routing.','{\"files_modified\": [\"app/Http/Controllers/Admin/DatabaseController.php\", \"resources/views/admin/pages/database/query.blade.php\", \"routes/admin.php\", \"resources/views/admin/pages/database/partials/database_summary.blade.php\", \"resources/views/admin/pages/database/partials/import_tab.blade.php\", \"resources/views/admin/pages/database/partials/export_tab.blade.php\", \"resources/views/admin/pages/database/partials/history_tab.blade.php\"]}','2026-02-19 09:50:00');
INSERT INTO `tbl_changelog` VALUES('12','office','1.2.3','Admin Menu Reorganization & Backup Integration','Restructured admin sidebar into logical groups (Main, Access, Tools, Logs, Settings) and renamed System Logs to ChangeLog. Integrated backup system with changelog, adding automated capture of new updates into backup descriptions with UI visibility in History and Restore views.','{\"files_modified\": [\"CHANGELOG.md\"]}','2026-02-20 18:35:00');
INSERT INTO `tbl_changelog` VALUES('13','office','1.2.4','Database Manager: Refactoring, Memory Safe Export & UI Polish','- **Dashboard Refresh**: Styled the main database table list overview with softer border-radiuses, improved spacing, refined typographic fonts, and added a subtle transition lifting effect when hovering over the main system stats cards. Replaced hard black pagination and search borders with slightly shadowed variants.
