INSERT INTO `tbl_changelog` VALUES('20','apps','2026.03.08','Agent Module Review + Login Tracking System','Agent Module:\\n- Fixed BelongsToCompany bugs on PartnerBankAccount & PartnerDocument\\n- Fixed double padding on all 7 agent views\\n- Added browser tab titles to all agent pages\\n- Added withQueryString() to pagination\\n- Removed duplicate flash messages\\n- Aligned agent views to match product module styling\\n\\nLogin Tracking:\\n- New tbl_admin_activity_log table for company admin logins\\n- Enhanced tbl_partner_activity_log with geo columns\\n- Tracking: IP, user agent, lat/long, geo info (city, country, ISP/APN)\\n- GeoIpService for IP geolocation lookup\\n- Browser geolocation capture on login forms','{\"deployed_files\":20,\"method\":\"smart_deploy\"}','2026-03-08 17:50:00');
